 1→import React from 'react';
 2→
 3→import { PropsTokenColorsCore } from '../../../styles/Models/type.colors';
 4→
 5→import { buttonOptions } from '../../constants/Tokens/tokens';
 6→import { PropsButton } from './Models';
 7→import ButtonView from './view';
 8→
 9→function Button({
10→  mb,
11→  ml,
12→  mr,
13→  mt,
14→  testID,
15→  width,
16→  accessibility = false,
17→  type = 'primaryLarge',
18→  text,
19→  disabled,
20→  contrast,
21→  icon,
22→  isLoading,
23→  onPress,
24→}: PropsButton) {
25→  const isSecondaryButton = [
26→    type === 'secundaryLarge',
27→    type === 'secundaryMedium',
28→    type === 'secundarySmall',
29→    type === 'secondaryNano',
30→    type === 'secundaryBrandSmall',
31→    type === 'secundaryBrandLarge',
32→    type === 'secundaryBrandMedium',
33→    type === 'secundaryBrandNano',
34→  ].some(Boolean);
35→  const textColorComponent = (): PropsTokenColorsCore => {
36→    if (isSecondaryButton && contrast && disabled) {
37→      return buttonOptions(type)?.text?.textColorContrastDisabled;
38→    }
39→    if (isSecondaryButton && contrast) {
40→      return buttonOptions(type)?.text?.textColorContrast;
41→    }
42→    if (contrast) {
43→      return 'PRYMARY_BASE_02';
44→    }
45→    if (disabled) {
46→      return buttonOptions(type)?.text.textColorDisabled;
47→    }
48→    return buttonOptions(type)?.text.textColor;
49→  };
50→
51→  const iconColorComponent = (): PropsTokenColorsCore => {
52→    if (isSecondaryButton && contrast && disabled) {
53→      return buttonOptions(type)?.icon?.iconColorContrastDisabled;
54→    }
55→    if (isSecondaryButton && contrast) {
56→      return buttonOptions(type)?.icon?.iconColorContrast;
57→    }
58→    if (contrast) {
59→      return 'BRAND_BASE_01';
60→    }
61→    if (disabled) {
62→      return buttonOptions(type)?.icon?.colorDisabled;
63→    }
64→    if (buttonOptions(type)?.icon) {
65→      return buttonOptions(type)?.icon?.color;
66→    }
67→    return 'INTENSE_COLOR_01';
68→  };
69→
70→  return (
71→    <ButtonView
72→      mb={mb}
73→      ml={ml}
74→      mr={mr}
75→      mt={mt}
76→      testID={testID}
77→      width={width}
78→      accessibility={accessibility}
79→      type={type}
80→      text={text}
81→      disabled={disabled}
82→      contrast={contrast}
83→      icon={icon}
84→      isLoading={isLoading}
85→      isSecondaryButton={isSecondaryButton}
86→      textColorComponent={textColorComponent}
87→      iconColorComponent={iconColorComponent}
88→      onPress={onPress}
89→    />
90→  );
91→}
92→
93→export default Button;
