 18→const InvoiceCashbackOnboarding: FC<InvoiceCashbackProps> = ({ route }) => {
 19→  const { width } = Dimensions.get('window');
 20→
 21→  const {
 22→    pointsQuantity,
 23→    isLoadingBalance,
