 44→          },
 45→        );
 46→        hasFocused.current = true;
 47→      }
 48→      return () => {
 49→        hasFocused.current = false;
 50→      };
 51→    }, []),
 52→  );
 53→
 54→  const navigation = useNavigation<NavigationProp<PropsRootStack>>();
 55→
 56→  const conversionFactor = route?.params?.conversionFactor ?? 0;
 57→  const campaingId = route?.params?.campaingId ?? '';
 58→  const productCode = route?.params?.productCode ?? '';
 59→
 60→  const pointsQuantityValue = pointsQuantity || 0;
 61→
 62→  const handleGoBack = () => {
 63→    navigation.goBack();
 64→  };
 65→
 66→  const requestAll = useCallback(() => {
 67→    requestParameterization();
 68→    requestPointsProducts();
 69→  }, [
 70→    requestParameterization,
 71→    requestPointsProducts,
 72→  ]);
 73→
 74→  const handleRetry = () => {
 75→    if (isErrorParameterization) {
 76→      requestAll();
 77→    }
 78→  };
 79→
 80→  const handleContinue = () => {
 81→    navigation.navigate('InvoiceCashbackPoints', {
 82→      conversionFactor: conversionFactor,
 83→      campaingId: campaingId,
 84→      productCode: productCode,
 85→    });
 86→
 87→    eventSelectContent({
 88→      content_type: 'cta',
 89→      content_id: 'continuar',
 90→      location_1: 'monetizacao',
 91→      location_2: 'hub_recompensas_spmais',
 92→      location_3: 'desconto_fatura_onboarding',
 93→    });
 94→  };
 95→
 96→  const invoiceList = (): CashbackInvoiceItem[] => {
 97→    const finalPrice = pointsQuantityValue * conversionFactor;
 98→    const formattedPrice = new Intl.NumberFormat('pt-BR', {
 99→      style: 'currency',
100→      currency: 'BRL',
101→    }).format(finalPrice);
102→
103→    return [
104→      {
105→        type: 'default',
106→        icon: 'icon-switch-vertical',
107→        iconColor: 'BRAND_BASE_01',
108→        iconColorShape: 'INTENSE_COLOR_01',
109→        description: `Cada ${pointsQuantityValue} pontos valem ${formattedPrice} no cashback`,
110→      },
111→      {
112→        type: 'default',
113→        icon: 'icon-calendar',
114→        iconColor: 'BRAND_BASE_01',
115→        iconColorShape: 'INTENSE_COLOR_01',
116→        description:
117→          'Você define quanto cashback quer aplicar na sua fatura aberta',
118→      },
119→      {
120→        type: 'default',
121→        icon: 'icon-payment-invoice',
122→        iconColor: 'BRAND_BASE_01',
123→        iconColorShape: 'INTENSE_COLOR_01',
124→        description:
125→          'Se o valor for maior que o da fatura, a diferença será aplicada nas próximas',
126→      },
127→      {
128→        type: 'default',
129→        icon: 'icon-clock',
130→        iconColor: 'BRAND_BASE_01',
131→        iconColorShape: 'INTENSE_COLOR_01',
132→        description: 'O cashback acontece em até 72h',
133→      },
134→    ];
135→  };
136→
137→  const items: CashbackInvoiceItem[] = invoiceList();
138→
139→  useEffect(() => {
140→    requestParameterization();
141→  }, [
142→    requestParameterization,
143→    refresh,
144→  ]);
145→
146→  if (isErrorParameterization) {
147→    return (
148→      <BasicScreen
149→        leftIconOnPress={handleGoBack}
150→        title="Cashback na fatura"
151→        errorButtonOnPress={handleRetry}
152→      >
153→        <ApiError onPress={handleRetry} />
154→      </BasicScreen>
155→    );
156→  }
157→  return (
158→    <InvoiceCashbackView
159→      handleGoBack={handleGoBack}
160→      handleContinue={handleContinue}
161→      handleRetry={handleRetry}
162→      items={items}
163→      hasError={isErrorBalance}
164→      hasLoading={isLoadingBalance}
165→      cashbackInvoiceList={invoiceList()}
166→      width={width}
167→      isLoadingParameterization={isLoadingParameterization}
168→    />
169→  );
170→};
171→
172→export default InvoiceCashbackOnboarding;
